async (params, browser) => {
  // Open StockX page
  await browser.open(`https://stockx.com/${params.product_slug}`)

  // Wait for page
  await browser.waitForSelector('h1[data-component=\'primary-product-title\'], h1, [data-testid=\'product-name\']', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`let schema = {}; try { const schemaEl = document.querySelector('script[data-testid="product-schema"]'); if (schemaEl) schema = JSON.parse(schemaEl.textContent); } catch(e) {} const name = document.querySelector('h1[data-component="primary-product-title"], h1')?.textContent?.trim() || schema.name || ''; const prices = {}; document.querySelectorAll('[class*="price"], [class*="stat"], [data-testid*="price"]').forEach(el => { const label = el.querySelector('span:first-child, dt, label')?.textContent?.trim()?.toLowerCase() || ''; const value = el.querySelector('span:last-child, dd, [class*="amount"]')?.textContent?.trim() || el.textContent?.trim() || ''; if (label) prices[label] = value; }); const details = {}; document.querySelectorAll('[class*="detail"], [class*="trait"]').forEach(el => { const label = el.querySelector('span:first-child, dt')?.textContent?.trim()?.toLowerCase() || ''; const value = el.querySelector('span:last-child, dd')?.textContent?.trim() || ''; if (label) details[label] = value; }); const image = schema.image || document.querySelector('img[data-testid="product-image"], [class*="product"] img')?.src || ''; return { name, prices, details, image, url: window.location.href };`)

  return result
}
